// scripts/firebase/guillotine-csv-to-firestore.js
// Updates the DEV Firestore with inflated stats from CSS files generated by
// guillotine-inflate-stats.js.  Only updates the fields that changed —
// headCount per head, and 4 aggregate fields on the main stats document.
//
// ⚙️  Set HEADS_CSV and STATS_CSV below to point at whichever files you want.
//
// Usage: node scripts/firebase/guillotine-csv-to-firestore.js

import admin from "firebase-admin";
import { readFileSync, existsSync } from "fs";
import { fileURLToPath } from "url";
import { dirname, join } from "path";
import chalk from "chalk";
import Table from "cli-table3";
import { loadServiceAccount, createProgressBar } from "../shared/utils.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// ---------------------------------------------------------------------------
// ⚙️  CONFIGURATION — point these at the CSV files you want to load
// ---------------------------------------------------------------------------

const CSV_DIR = join(__dirname, "../csv/stats");

/** CSV containing inflated head records (columns: name, headCount, ...) */
const HEADS_CSV = join(CSV_DIR, "guillotine-heads-inflated.csv");

/** CSV containing inflated stats document (columns: gamesStarted, ...) */
const STATS_CSV = join(CSV_DIR, "guillotine-stats-inflated.csv");

// ---------------------------------------------------------------------------
// Firestore paths
// ---------------------------------------------------------------------------

const GUILLOTINE_STATS_DOC = "stats/guillotine";
const GUILLOTINE_HEADS_COL = "stats/guillotine/heads";

// Firestore allows 500 ops per batch; stay comfortably under that.
const BATCH_SIZE = 450;

// ---------------------------------------------------------------------------
// Firebase setup (dev only)
// ---------------------------------------------------------------------------

const devServiceAccount = loadServiceAccount("dev-service-account.json", __dirname);
const devApp = admin.initializeApp({ credential: admin.credential.cert(devServiceAccount) }, "development");
const devDb = devApp.firestore();

// ---------------------------------------------------------------------------
// CSV helpers
// ---------------------------------------------------------------------------

function parseCSVLine(line) {
  const fields = [];
  let current = "";
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === "," && !inQuotes) {
      fields.push(current);
      current = "";
    } else {
      current += ch;
    }
  }
  fields.push(current);
  return fields;
}

function parseCSV(content) {
  const lines = content.trim().split("\n");
  const headers = parseCSVLine(lines[0]);
  return lines.slice(1).map((line) => {
    const values = parseCSVLine(line);
    const obj = {};
    headers.forEach((h, i) => (obj[h.trim()] = values[i] !== undefined ? values[i].trim() : ""));
    return obj;
  });
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main() {
  console.log(chalk.bold.blue("\n🔥 Guillotine CSV → Firestore Updater\n"));
  console.log(chalk.gray(`   Project: ${devServiceAccount.project_id}`));
  console.log(chalk.gray(`   Heads CSV:  ${HEADS_CSV}`));
  console.log(chalk.gray(`   Stats CSV:  ${STATS_CSV}\n`));

  // -------------------------------------------------------------------------
  // 1. Validate input files exist
  // -------------------------------------------------------------------------
  const errors = [];

  if (!existsSync(HEADS_CSV)) {
    errors.push(`Missing: ${HEADS_CSV}`);
  }
  if (!existsSync(STATS_CSV)) {
    errors.push(`Missing: ${STATS_CSV}`);
  }

  if (errors.length > 0) {
    console.log(chalk.red("❌ Required CSV files not found:\n"));
    errors.forEach((e) => console.log(chalk.red(`   • ${e}`)));
    console.log(chalk.yellow("\n   Run guillotine-inflate-stats.js first to generate the inflated CSVs."));
    process.exit(1);
  }

  // -------------------------------------------------------------------------
  // 2. Parse CSV files
  // -------------------------------------------------------------------------
  console.log(chalk.yellow("📂 Reading CSV files..."));

  const headRows = parseCSV(readFileSync(HEADS_CSV, "utf8"));
  const statsRows = parseCSV(readFileSync(STATS_CSV, "utf8"));

  if (headRows.length === 0) {
    console.log(chalk.red("❌ Heads CSV is empty."));
    process.exit(1);
  }
  if (statsRows.length === 0) {
    console.log(chalk.red("❌ Stats CSV is empty."));
    process.exit(1);
  }

  // Validate numeric fields
  const invalidHeadRows = headRows.filter((row) => !row.name || row.headCount === "" || isNaN(Number(row.headCount)));
  if (invalidHeadRows.length > 0) {
    console.log(chalk.red(`❌ ${invalidHeadRows.length} head row(s) have missing or non-numeric headCount.`));
    invalidHeadRows.slice(0, 5).forEach((r) => console.log(chalk.red(`   • "${r.name}": headCount="${r.headCount}"`)));
    process.exit(1);
  }

  const statsRow = statsRows[0];
  const newGamesStarted = Number(statsRow.gamesStarted);
  const newGamesFinished = Number(statsRow.gamesFinished);
  const newScoresShared = Number(statsRow.scoresShared);
  const newWealthCreated = Number(statsRow.wealthCreated);

  if ([newGamesStarted, newGamesFinished, newScoresShared, newWealthCreated].some(isNaN)) {
    console.log(chalk.red("❌ Stats CSV contains non-numeric values for numeric fields."));
    console.log(
      chalk.red(
        `   gamesStarted="${statsRow.gamesStarted}", gamesFinished="${statsRow.gamesFinished}", scoresShared="${statsRow.scoresShared}", wealthCreated="${statsRow.wealthCreated}"`,
      ),
    );
    process.exit(1);
  }

  console.log(chalk.green(`   ✅ ${headRows.length} head records ready.\n`));

  // -------------------------------------------------------------------------
  // 3. Preview what will be written
  // -------------------------------------------------------------------------
  const previewTable = new Table({
    head: [chalk.white("Document / Field"), chalk.white("New Value")],
    style: { head: [] },
  });

  previewTable.push([chalk.bold("/stats/guillotine"), ""]);
  previewTable.push(["  gamesStarted", chalk.green(newGamesStarted.toLocaleString())]);
  previewTable.push(["  gamesFinished", chalk.green(newGamesFinished.toLocaleString())]);
  previewTable.push(["  scoresShared", chalk.green(newScoresShared.toLocaleString())]);
  previewTable.push(["  wealthCreated", chalk.green(newWealthCreated.toLocaleString())]);
  previewTable.push([chalk.bold(`/stats/guillotine/heads (${headRows.length.toLocaleString()} docs)`), chalk.gray("headCount only")]);
  previewTable.push(["  Batch size", BATCH_SIZE.toLocaleString()]);
  previewTable.push(["  Batches required", String(Math.ceil(headRows.length / BATCH_SIZE))]);

  console.log(chalk.yellow("📋 Planned changes:\n"));
  console.log(previewTable.toString());
  console.log(chalk.bold.yellow(`\n⚠️  This will write to DEVELOPMENT Firestore (${devServiceAccount.project_id}).`));
  console.log(chalk.bold.yellow("   Production is NOT affected.\n"));

  // -------------------------------------------------------------------------
  // 4. Update head documents in batches
  // -------------------------------------------------------------------------
  console.log(chalk.yellow("🔄 Updating head documents...\n"));

  const chunks = [];
  for (let i = 0; i < headRows.length; i += BATCH_SIZE) {
    chunks.push(headRows.slice(i, i + BATCH_SIZE));
  }

  let totalWritten = 0;

  const headBar = createProgressBar("Updating heads");
  headBar.start(headRows.length, 0);

  for (const chunk of chunks) {
    const batch = devDb.batch();
    for (const row of chunk) {
      const docRef = devDb.doc(`${GUILLOTINE_HEADS_COL}/${row.name}`);
      // update() only touches headCount; all other fields remain unchanged.
      batch.update(docRef, { headCount: Number(row.headCount) });
    }
    await batch.commit();
    totalWritten += chunk.length;
    headBar.update(totalWritten);
  }
  headBar.stop();

  console.log(chalk.green(`\n✅ Updated ${totalWritten.toLocaleString()} head documents across ${chunks.length} batch(es).`));

  // -------------------------------------------------------------------------
  // 5. Update the main stats document (4 fields only)
  // -------------------------------------------------------------------------
  console.log(chalk.yellow("\n📊 Updating /stats/guillotine..."));

  await devDb.doc(GUILLOTINE_STATS_DOC).update({
    gamesStarted: newGamesStarted,
    gamesFinished: newGamesFinished,
    scoresShared: newScoresShared,
    wealthCreated: newWealthCreated,
  });

  console.log(chalk.green("✅ Updated /stats/guillotine.\n"));

  // -------------------------------------------------------------------------
  // 6. Final summary
  // -------------------------------------------------------------------------
  const summaryTable = new Table({
    head: [chalk.white("Action"), chalk.white("Count"), chalk.white("Status")],
    style: { head: [] },
  });

  summaryTable.push(["Head documents updated", totalWritten.toLocaleString(), chalk.green("✅ Done")]);
  summaryTable.push(["Stats document updated", "1", chalk.green("✅ Done")]);
  summaryTable.push(["Write batches used", chunks.length.toLocaleString(), chalk.green("✅ Done")]);
  summaryTable.push(["Writes to prod", "0", chalk.green("✅ Safe")]);

  console.log(summaryTable.toString());
  console.log(chalk.bold.green("\n✅ Firestore update complete!\n"));

  process.exit(0);
}

main().catch((err) => {
  console.error(chalk.red("\n❌ Error:"), err);
  process.exit(1);
});
